ge">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Anti-luteinizing hormone (LH) shows cytoplasmic positivity in pituitary gland.','https://www.cellmarque.com/antibodies/CM/110/LH_polyclonal','#','https://www.cellmarque.com/cmsial-images/TH_209A-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-110-lh-polyclonal-453C0258',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/110/LH_polyclonal');
