body-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/136/PSAP_PASE-4LJ" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Benign prostate glandular cells are labelled by PSAP antibody.','https://www.cellmarque.com/antibodies/CM/136/PSAP_PASE-4LJ','#','https://www.cellmarque.com/cmsial-images/TH_326M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-136-psap-pase-4lj-708E4B7D',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/136/PSAP_PASE-4LJ');
