 href="https://www.cellmarque.com/antibodies/CM/142/TAG-72_B72-3" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','TAG-72 antibody labels the cytoplasm of colon adenocarcinoma in a somewhat variable fashion.','https://www.cellmarque.com/antibodies/CM/142/TAG-72_B72-3','#','https://www.cellmarque.com/cmsial-images/TH_337M-8-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-142-tag-72-b72-3-ED6DE447',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/142/TAG-72_B72-3');
Insert into WEB.PRODUCTS_STAGING (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7534','TTF-1',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>8G7G3/1</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Mouse</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Anatomic Pathology • Pulmonary Pathology</td></tr>        <tr><th>Visualization:</th><td></td></tr>        <tr><th>Control:</th><td>Lung Adenocarcinoma (Nuclear)</td></tr>        <tr><th>Dilution Range:</th><td>1:100-1:500*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Thyroid transcription factor-1 (TTF-1) is a transcription factor that plays a role in regulating genes expressed within the thyroid, lung, and brain. TTF-1 expression is present in normal thyroid epithelium and type II pneumocytes and nonciliated bronchiolar secretory cells of the lung. TTF-1 expression is seen in most primary lung and thyroid carcinomas, but rarely in other carcinomas. Anti-TTF-1 immunohistochemistry is useful for identifying carcinomas of thyroid and lung origin.1-9</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/148/TTF-1_8G7G3-1" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Nuclear labelling of lung adenocarcinoma by TTF-1 antibody.','https://www.cellmarque.com/antibodies/CM/148/TTF-1_8G7G3-1','#','https://www.cellmarque.com/cmsial-images/TH_343M-9-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-148-ttf-1-8g7g3-1-F1346EC0',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/148/TTF-1_8G7G3-1');
Insert into WEB.PRODUCTS_STAGING (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7540','Alpha-Fetoprotein',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>Polyclonal</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Rabbit</td></tr>        <tr><th>Antibody Type:</th><td>Polyclonal</td></tr>        <tr><th>Specialties:</th><td>Anatomic Pathology • Genitourinary (GU) Pathology</td></tr>        <tr><th>Visualization:</th><td></td></tr>        <tr><th>Control:</th><td>Fetal Liver (Cytoplasmic)</td></tr>        <tr><th>Dilution Range:</th><td>1:50-1:200*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Alpha-fetoprotein (AFP) is a fetal tumor-associated polypeptide of the albuminoid gene family that binds and transports molecules in addition to many other proposed functions.1This secretory protein is produced by the fetal yolk sac and liver but is found only in trace amounts in adult liver.2AFP expression by immunohistochemistry is seen in hepatocellular carcinoma (HCC).3 Note:This product is in obsolescence.Alpha-Fetoprotein (EP209)is available as an alternative.</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/16/Alpha-Fetoprotein_Polyclonal" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Alpha-fetoprotein antibody picks up fetal liver cells in a strong cytoplasmic staining reaction.','https://www.cellmarque.com/antibodies/CM/16/Alpha-Fetoprotein_Polyclonal','#','https://www.cellmarque.com/cmsial-images/TH_203A-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-16-alpha-fetoprotein-polyclonal-94FD7BCD',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/16/Alpha-Fetoprotein_Polyclonal');
