e="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','CD5 (SP19) on tonsil.','https://www.cellmarque.com/antibodies/CM/1931/CD5_SP19','#','https://www.cellmarque.com/cmsial-images/TH_205R-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-1931-cd5-sp19-0A59D4E6',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/1931/CD5_SP19');
