iv class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/1981/Oct-4_MRQ-10" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Oct-4 antibody labels seminoma cells in a nuclear pattern.','https://www.cellmarque.com/antibodies/CM/1981/Oct-4_MRQ-10','#','https://www.cellmarque.com/cmsial-images/TH_309M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-1981-oct-4-mrq-10-DC831FBB',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/1981/Oct-4_MRQ-10');
