/div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2148/Napsin-A_MRQ-60" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Lung adenocarcinoma tumor cells are stained by anti-napsin A.','https://www.cellmarque.com/antibodies/CM/2148/Napsin-A_MRQ-60','#','https://www.cellmarque.com/cmsial-images/TH_352M-9-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2148-napsin-a-mrq-60-9C61CE45',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/2148/Napsin-A_MRQ-60');
