     </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2163/MyoD1_EP212" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Rhabdomyosarcoma cells are labeled in a nuclear pattern by anti-MyoD1.','https://www.cellmarque.com/antibodies/CM/2163/MyoD1_EP212','#','https://www.cellmarque.com/cmsial-images/TH_386R-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2163-myod1-ep212-21166208',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/2163/MyoD1_EP212');
