class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2172/TLE1_1F5" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','TLE1 antibody labels the nuclei in tumor cells of synovial sarcoma.','https://www.cellmarque.com/antibodies/CM/2172/TLE1_1F5','#','https://www.cellmarque.com/cmsial-images/TH_401M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2172-tle1-1f5-A97E135E',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/2172/TLE1_1F5');
Insert into WEB.PRODUCTS_STAGING (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7683','CD4',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>EP204</td></tr>        <tr><th>Brand:</th><td>CM + RabMAb</td></tr>        <tr><th>Host:</th><td>Rabbit</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Hematopathology</td></tr>        <tr><th>Visualization:</th><td>cytoplasmic, membranous</td></tr>        <tr><th>Control:</th><td>tonsil, lymph node</td></tr>        <tr><th>Dilution Range:</th><td>1:25-1:100*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">CD4 is a 55 kD glycoprotein expressed on the surface of T-helper/regulatory T-cells, monocytes, macrophages, and dendritic cells. Anti-CD4 is used in the immunophenotyping of lymphoproliferative disorders.1The majority of peripheral T-cell lymphomas are derived from the T-helper/regulatory cell subset so that most mature T-cell neoplasms are CD4+ CD8-.2As with other T-cell antigens, CD4 may be aberrantly expressed in neoplastic T-cells so that the evaluation of such tumors requires the application of a panel of markers in order to identify tumors with CD4 aberrant expression.1-3</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2186/CD4_EP204" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Interfollicular T-lymphocytes express CD4 antigen in the cytoplasm of the lymphocytes.','https://www.cellmarque.com/antibodies/CM/2186/CD4_EP204','#','https://www.cellmarque.com/cmsial-images/TH_104R-2-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2186-cd4-ep204-8AD63063',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/2186/CD4_EP204');
Insert into WEB.PRODUCTS_STAGING (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7688','Kappa',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>EP171</td></tr>        <tr><th>Brand:</th><td>CM + RabMAb</td></tr>        <tr><th>Host:</th><td>Rabbit</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Hematopathology</td></tr>        <tr><th>Visualization:</th><td>cytoplasmic</td></tr>        <tr><th>Control:</th><td>tonsil</td></tr>        <tr><th>Dilution Range:</th><td>1:100-1:500*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Anti-Kappa detects surface immunoglobulin on normal and neoplastic B-cells. In paraffin-embedded tissue, anti-kappa exhibits strong staining of kappa-positive plasma cells and cells that have absorbed exogenous immunoglobulins. When dealing with B-cell neoplasms, the determination of light chain ratios remains the centerpiece. Most B-cell lymphomas express either kappa or lambda light chains, whereas reactive proliferations display a mixture of kappa and lambda positive cells. If only a single light chain type is detected, a lymphoproliferative disorder exists.1-3 Note:This product is in obsolescence.Kappa (L1C1)is available as an alternative.</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2196/Kappa_EP171" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Kappa (EP171) on tonsil.','https://www.cellmarque.com/antibodies/CM/2196/Kappa_EP171','#','https://www.cellmarque.com/cmsial-images/TH_274R-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2196-kappa-ep171-A28862D8',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/2196/Kappa_EP171');
Insert into WEB.PRODUCTS_STAGING (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7695','Napsin A',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>EP205</td></tr>        <tr><th>Brand:</th><td>CM + RabMAb</td></tr>        <tr><th>Host:</th><td>Rabbit</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Cytopathology • Pulmonary Pathology</td></tr>        <tr><th>Visualization:</th><td>cytoplasmic</td></tr>        <tr><th>Control:</th><td>lung adenocarcinoma, kidney, renal cell carcinoma</td></tr>        <tr><th>Dilution Range:</th><td>1:100-1:500*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Napsin is a pepsin-like aspartic proteinase in the A1 clan of the AA clade of proteinases.1-3There are two closely related napsins, napsin A (NAPSA) and napsin B (NAPSB).1-3Napsin A is involved in processing propeptide pulmonary surfactant protein B (proSP-B) in the lung.4In normal tissue, Napsin A is expressed in type II pneumocytes of the lung and proximal tubules of the kidney.1-3Napsin A is a useful marker for lung adenocarcinoma.1-3, 5-8 Note:This product is in obsolescence.Napsin A (MRQ-60)is available as an alternative.</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2207/Napsin-A_EP205" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Lung adenocarcinoma tumor cells are stained by anti-napsin A.','https://www.cellmarque.com/antibodies/CM/2207/Napsin-A_EP205','#','https://www.cellmarque.com/cmsial-images/TH_352R-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2207-napsin-a-ep205-A6882B04',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/2207/Napsin-A_EP205');
Insert into WEB.PRODUCTS_STAGING (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7700','CA19-9',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>121SLE</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Mouse</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Anatomic Pathology • Gastrointestinal (GI) Pathology</td></tr>        <tr><th>Visualization:</th><td></td></tr>        <tr><th>Control:</th><td>Colon (Cytoplasmic)</td></tr>        <tr><th>Dilution Range:</th><td>1:25-1:100*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Carbohydrate Antigen 19-9 (CA19-9) is a sialylated Lewis A blood group antigen.1It is synthesized by glycosyltransferases and has been identified as a component of gangliosides, glycoproteins and mucins.1,2Anti-CA19-9 reacts with epithelial cells of normal pancreas, stomach, and colon as well as various adenocarcinomas, including pancreatic, gastric, and colorectal adenocarcinomas.3,4</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/26/CA19-9_121SLE" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Colon adenocarcinoma cells show a strong cytoplasmic reaction to the CA 19-9 protein.','https://www.cellmarque.com/antibodies/CM/26/CA19-9_121SLE','#','https://www.cellmarque.com/cmsial-images/TH_399M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-26-ca19-9-121sle-2D108720',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/26/CA19-9_121SLE');
Insert into WEB.PRODUCTS_STAGING (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7641','LMO2',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>SP51</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Rabbit</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Hematopathology</td></tr>        <tr><th>Visualization:</th><td>nuclear</td></tr>        <tr><th>Control:</th><td>tonsil, follicular lymphoma, diffuse large B-cell lymphoma</td></tr>        <tr><th>Dilution Range:</th><td>1:500-1:2000*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">The LIM-domain-only (LMO) family of proteins function as linkers in the co-regulation of nuclear transcription by mediating protein-protein interactions. The four members of the LMO family collectively have significant roles in cell fate determination, cell growth and differentiation, and organ development.1LMO2 has a particular function in normal and lymphatic endothelial cells involving the regulation of angiogenesis and lymphangiogenesis.2Immunohistochemical studies have also demonstrated expression of LMO2 in both normal germinal center B-cells and germinal center-derived B-cell lymphomas, including follicular lymphoma and diffuse large B-cell lymphoma.3The use of anti-LMO2 is valuable as a tool in the identification of lymphomas of B-cell origin.</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2120/LMO2_SP51" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','LMO2 monoclonal antibody demonstrates nuclear positivity in follicular lymphoma cells.','https://www.cellmarque.com/antibodies/CM/2120/LMO2_SP51','#','https://www.cellmarque.com/cmsial-images/TH_370R-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2120-lmo2-sp51-001B9677',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/2120/LMO2_SP51');
Insert into WEB.PRODUCTS_STAGING (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7647','PAX-8',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>MRQ-50</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Mouse</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Anatomic Pathology</td></tr>        <tr><th>Visualization:</th><td></td></tr>        <tr><th>Control:</th><td>Ovarian carcinoma (non-mucinous carcinoma) (Nuclear); Thyroid carcinoma (Nuclear); Renal cell carcinoma (Nuclear)</td></tr>        <tr><th>Dilution Range:</th><td>1:50-1:200*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">PAX-8 is a transcription factor expressed during embryonic development of Müllerian organs, kidney, and thyroid, with continued expression in some epithelial cell types of these mature tissues.1PAX-8 is a useful marker for neoplasms of gynecologic,2,5,7,10renal,3-9and thyroid origin.1,4,5,7 PAX-8 (MRQ-50) antibody targets the N-terminus of the PAX-8 molecule. This section of the protein is shared with other PAX proteins such as PAX-5 and PAX-6; and thus, some cross-reactivity with these proteins may be observed as evidenced by labeling of selected lymphocytes, and neuroendocrine cells.7</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2127/PAX-8_MRQ-50" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','PAX-8 antibody labels the tumor nuclei in clear cell renal cell carcinoma.','https://www.cellmarque.com/antibodies/CM/2127/PAX-8_MRQ-50','#','https://www.cellmarque.com/cmsial-images/TH_363M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2127-pax-8-mrq-50-E65D4F1A',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/2127/PAX-8_MRQ-50');
Insert into WEB.PRODUCTS_STAGING (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7652','CD11c',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>5D11</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Mouse</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Hematopathology</td></tr>        <tr><th>Visualization:</th><td>cytoplasmic</td></tr>        <tr><th>Control:</th><td>hairy cell leukemia, granulocytes, monocytes, bone marrow</td></tr>        <tr><th>Dilution Range:</th><td>1:20-1:80*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">CD11c is an adhesion receptor of the leukocyte function-associated family of molecules. Reportedly CD11c is expressed in hairy cell leukemia whereas the majority of other small B-cell lymphomas do not express CD11c antigen. This indicates that immunohistochemical staining of formalin-fixed biopsies with anti-CD11c can be useful for identification of hairy cell leukemia.1-4</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2134/CD11c_5D11" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Hairy cell leukemia cells show a moderate membranous staining reaction by CD11c antibody.','https://www.cellmarque.com/antibodies/CM/2134/CD11c_5D11','#','https://www.cellmarque.com/cmsial-images/TH_111M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2134-cd11c-5d11-E56369CE',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/2134/CD11c_5D11');
Insert into WEB.PRODUCTS_STAGING (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7581','INI-1',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>MRQ-27</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Mouse</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Pediatric Pathology</td></tr>        <tr><th>Visualization:</th><td></td></tr>        <tr><th>Control:</th><td>Brain (Nuclear); Endothelial cells (Nuclear); Astrocytoma (Nuclear)</td></tr>        <tr><th>Dilution Range:</th><td>1:100-1:500*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">INI-1, also known as SMARCB1, is one of the core subunit proteins of the ATP-dependent SWI/SNF chromatin remodeling complex. It is involved in chromatin remodeling and transcriptional regulation and functions as a tumor suppressor. Nuclear INI-1 expression is seen in virtually all normal human tissues and most malignancies but the INI-1 gene is often mutated or deleted in malignant rhabdoid tumors (MRT), including those arising in the central nervous system, leading to a lack of INI-1 expression.1-3</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2012/INI-1_MRQ-27" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','INI-1 antibody shows nuclear reaction in neuronal cells in the brain.','https://www.cellmarque.com/antibodies/CM/2012/INI-1_MRQ-27','#','https://www.cellmarque.com/cmsial-images/TH_272M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2012-ini-1-mrq-27-68D00526',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/2012/INI-1_MRQ-27');
Insert into WEB.PRODUCTS_STAGING (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7587','Parathyroid Hormone (PTH)',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>MRQ-31</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Mouse</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Head/Neck Pathology</td></tr>        <tr><th>Visualization:</th><td>cytoplasmic, membranous</td></tr>        <tr><th>Control:</th><td>parathyroid tissue</td></tr>        <tr><th>Dilution Range:</th><td>1:100-1:500*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">The parathyroid glands function within the endocrine system to promote blood calcium homeostasis through controlled release of parathyroid hormone (PTH). This process involves the synthesis and secretion of PTH by activated parathyroid chief cells during conditions of hypocalcemia.1With the anatomical proximity to the thyroid and capacity of associated neoplasms of the parathyroid to mimic thyroid tumors, challenges can arise in distinguishing between these types of abnormalities. In cases where there is uncertainty about a tumor being of parathyroid origin, immunohistochemical evaluation using anti-PTH can be of value.2,3</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2020/Parathyroid-Hormone-PTH_MRQ-31" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Anti-PTH labels hyperplastic parathyroid glands in a cytoplasmic pattern.','https://www.cellmarque.com/antibodies/CM/2020/Parathyroid-Hormone-PTH_MRQ-31','#','https://www.cellmarque.com/cmsial-images/TH_310M-2-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2020-parathyroid-hormone-pth-mrq-31-D56CD76F',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/2020/Parathyroid-Hormone-PTH_MRQ-31');
Insert into WEB.PRODUCTS_STAGING (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7592','Oct-2',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>MRQ-2</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Mouse</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Hematopathology</td></tr>        <tr><th>Visualization:</th><td></td></tr>        <tr><th>Control:</th><td>Tonsil (Nuclear); Lymph node (Nuclear)</td></tr>        <tr><th>Dilution Range:</th><td>1:25-1:100*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Octamer-binding transcription factor-2 (Oct-2) is a transcription factor of the POU homeo-domain family. It binds to Ig gene octamer sites and plays a crucial role in B-cell development and differentiation, as well as in B-cell identity.1Oct-2 is expressed in a subset of normal B-lymphocytes and is expressed in various B-cell lymphomas as well as nodular lymphocyte predominant Hodgkin lymphoma, while it is typically not expressed in the Reed–Sternberg and Hodgkin (RS/H) cells of classical Hodgkin lymphoma.1-3</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2028/Oct-2_MRQ-2" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Lymphoma cells are expressed in diffuse large B-cell lymphoma in a nuclear reaction by Oct-2 antibody.','https://www.cellmarque.com/antibodies/CM/2028/Oct-2_MRQ-2','#','https://www.cellmarque.com/cmsial-images/TH_308M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2028-oct-2-mrq-2-E83A66FE',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/2028/Oct-2_MRQ-2');
Insert into WEB.PRODUCTS_STAGING (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7596','PAX-5',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>SP34</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Rabbit</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Hematopathology</td></tr>        <tr><th>Visualization:</th><td>nuclear</td></tr>        <tr><th>Control:</th><td>tonsil</td></tr>        <tr><th>Dilution Range:</th><td>1:100-1:500*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">PAX-5 encodes for transcription factor B-cell-specific activator protein (BSAP) and has a central role in B-cells proliferation and differentiation, as well as midbrain development1. Anti-PAX-5 has been shown to be a useful marker for B-cell malignancies.1-3</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2033/PAX-5_SP34" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','PAX-5 antibody has a strong nuclear expression for Reed-Sternberg cells and B-lymphocytes in Hodgkin lymphoma.','https://www.cellmarque.com/antibodies/CM/2033/PAX-5_SP34','#','https://www.cellmarque.com/cmsial-images/TH_312R-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2033-pax-5-sp34-E2FAD4D0',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/2033/PAX-5_SP34');
Insert into WEB.PRODUCTS_STAGING (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7601','Napsin A',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>Polyclonal</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Rabbit</td></tr>        <tr><th>Antibody Type:</th><td>Polyclonal</td></tr>        <tr><th>Specialties:</th><td>Cytopathology • Pulmonary Pathology</td></tr>        <tr><th>Visualization:</th><td></td></tr>        <tr><th>Control:</th><td>Lung Adenocarcinoma (Cytoplasmic); Kidney (Cytoplasmic)</td></tr>        <tr><th>Dilution Range:</th><td>1:100-1:500*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Napsin is a pepsin-like aspartic proteinase in the A1 clan of the AA clade of proteinases.1-3Napsin A is involved in processing propeptide pulmonary surfactant protein B (proSP-B) in the lung.4In normal, benign tissue, Napsin A is expressed in type II pneumocytes of the lung and proximal tubules of the kidney. Napsin A is a useful marker for lung adenocarcinoma.1-3, 5-8The polyclonal Napsin A antibody exhibits cross reactivity with a number of non-pulmonary carcinomas such as colorectal carcinoma and renal cell carcinoma.9Due to this cross reactivity, this product is not recommended to be used for differentiation between pulmonary and colorectal adenocarcinomas.</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2050/Napsin-A_Polyclonal" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Anti-napsin A labels lung adenocarcinoma tumor cells.','https://www.cellmarque.com/antibodies/CM/2050/Napsin-A_Polyclonal','#','https://www.cellmarque.com/cmsial-images/TH_352A-7-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2050-napsin-a-polyclonal-AD9B944C',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/2050/Napsin-A_Polyclonal');
Insert into WEB.PRODUCTS_STAGING (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7606','Claudin 1',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>polyclonal</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Rabbit</td></tr>        <tr><th>Antibody Type:</th><td>Polyclonal</td></tr>        <tr><th>Specialties:</th><td>Anatomic Pathology</td></tr>        <tr><th>Visualization:</th><td>membranous</td></tr>        <tr><th>Control:</th><td>neurofibroma, colon carcinoma</td></tr>        <tr><th>Dilution Range:</th><td>1:25-1:100*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Claudins are a family of over twenty proteins which are components of tight junctions. Tight junctions are specialized regions of cell-to-cell contact made up of a network of strands to act as a molecular ‘gasket’ for preventing the leakage of ions, water, etc., between cells.1Claudin 1 has been shown to distinguish epithelial neoplasms from lymphomas, making it a useful marker for nearly all carcinomas.2</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2060/Claudin-1_polyclonal" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Anti-claudin 1 stains colon adenocarcinoma in a cell membranous pattern.','https://www.cellmarque.com/antibodies/CM/2060/Claudin-1_polyclonal','#','https://www.cellmarque.com/cmsial-images/TH_359A-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2060-claudin-1-polyclonal-C5396B51',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/2060/Claudin-1_polyclonal');
