>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/31/Calponin_CALP" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Myoepithelial cells of breast ducts are stained positive by anti-calponin in a cytoplasmic pattern.','https://www.cellmarque.com/antibodies/CM/31/Calponin_CALP','#','https://www.cellmarque.com/cmsial-images/TH_231M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-31-calponin-calp-D798BA40',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/31/Calponin_CALP');
