k" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Melanoma labelled by tyrosinase antibody.','https://www.cellmarque.com/antibodies/CM/149/Tyrosinase_T311','#','https://www.cellmarque.com/cmsial-images/TH_344M-9-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-149-tyrosinase-t311-AA9813AB',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/149/Tyrosinase_T311');
