dies/CM/131/PLAP_SP15" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Tumor cells on classical seminoma of testis express cytoplasmic staining of anti-PLAP.','https://www.cellmarque.com/antibodies/CM/131/PLAP_SP15','#','https://www.cellmarque.com/cmsial-images/TH_321R-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-131-plap-sp15-70674E17',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/131/PLAP_SP15');
Insert into WEB.PRODUCTS_STAGING (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7522','Prolactin',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>polyclonal</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Rabbit</td></tr>        <tr><th>Antibody Type:</th><td>Polyclonal</td></tr>        <tr><th>Specialties:</th><td>Anatomic Pathology • Neuropathology</td></tr>        <tr><th>Visualization:</th><td>cytoplasmic</td></tr>        <tr><th>Control:</th><td>pituitary</td></tr>        <tr><th>Dilution Range:</th><td>1:100-1:500*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Prolactin (PRL) is a single-chain polypeptide of 226 amino acids and plays a role in multiple processes including cell growth, reproduction, and immune function. Anti-Prolactin reacts with prolactin-producing cells and is a useful marker in classification of pituitary tumors and the study of pituitary disease.1-5 Note:This product is in obsolescence.Prolactin (EP193)is available as an alternative.</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/134/Prolactin_polyclonal" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Prolactin producing cells in pituitary gland labelled by prolactin antibody.','https://www.cellmarque.com/antibodies/CM/134/Prolactin_polyclonal','#','https://www.cellmarque.com/cmsial-images/TH_210A-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-134-prolactin-polyclonal-B8343BF1',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/134/Prolactin_polyclonal');
Insert into WEB.PRODUCTS_STAGING (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7523','PSA',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>ER-PR8</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Mouse</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Anatomic Pathology • Genitourinary (GU) Pathology</td></tr>        <tr><th>Visualization:</th><td>cytoplasmic</td></tr>        <tr><th>Control:</th><td>prostate, prostate carcinoma</td></tr>        <tr><th>Dilution Range:</th><td>1:50-1:200*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Prostate-Specific Antigen (PSA) is a 33 kDa protein primarily produced by the prostatic epithelium and the epithelial lining of the periurethral glands1. PSA is strongly expressed in both normal and neoplastic prostatic tissue. Although PSA can be considered prostate-specific, PSA and/or PSA gene expression has been detected at low levels in some extra-prostatic tissues such as normal breast tissue, breast tumors, endometrium, adrenal neoplasms and renal cell carcinomas1, 2, 3. Anti-PSA is most useful in determining the prostatic origin of carcinomas in non-prostate tissues (metastatic disease) using IHC techniques. This product is best used in conjunction with a panel of antibodies as, up to 27% of prostate carcinoma cases (predominantly poorly differentiated carcinomas) can be negative for this marker.4</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/135/PSA_ER-PR8" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Benign prostate gland epithelial cells are labelled with PSA antibody.','https://www.cellmarque.com/antibodies/CM/135/PSA_ER-PR8','#','https://www.cellmarque.com/cmsial-images/TH_324M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-135-psa-er-pr8-0142C0F9',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/135/PSA_ER-PR8');
Insert into WEB.PRODUCTS_STAGING (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7525','Renal Cell Carcinoma',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>PN-15</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Mouse</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Anatomic Pathology</td></tr>        <tr><th>Visualization:</th><td></td></tr>        <tr><th>Control:</th><td>Renal Cell Carcinoma (Cytoplasmic, Membranous)</td></tr>        <tr><th>Dilution Range:</th><td>1:50-1:200*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Anti-renal cell carcinoma (RCC) recognizes a 200 kD glycoprotein localized in the brush border of the proximal renal tubule.1This antibody immunoreacts with most primary renal cell carcinomas and can aid in the diagnosis when renal cell carcinoma enters the differential diagnosis.2-3</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/137/Renal-Cell-Carcinoma_PN-15" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Renal cell carcinoma tumor cells are labelled in a cytoplasmic pattern by anti-renal cell carcinoma.','https://www.cellmarque.com/antibodies/CM/137/Renal-Cell-Carcinoma_PN-15','#','https://www.cellmarque.com/cmsial-images/TH_329M-9-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-137-renal-cell-carcinoma-pn-15-0BAEF625',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/137/Renal-Cell-Carcinoma_PN-15');
Insert into WEB.PRODUCTS_STAGING (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7526','S-100',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>4C4.9</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Mouse</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Dermatopathology</td></tr>        <tr><th>Visualization:</th><td>cytoplasmic, nuclear</td></tr>        <tr><th>Control:</th><td>melanoma</td></tr>        <tr><th>Dilution Range:</th><td>1:50-1:200*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">S-100 protein has been found in normal melanocytes, Langerhans cells, histiocytes, chondrocytes, lipocytes, skeletal and cardiac muscle, Schwann cells, epithelial and myoepithelial cells of the breast, salivary and sweat glands, as well as in glial cells.1,2,6Neoplasms derived from these cells also express S-100 protein, albeit non-uniformly.1-4A large number of well differentiated tumors of the salivary gland, adipose and cartilaginous tissue,3and Schwann cell-derived tumors express S-100 protein. Almost all malignant melanomas and cases of histiocytosis X are positive for S-100 protein.4,5Despite the fact that S-100 protein is an ubiquitous substance, its demonstration is of great value in the identification of several neoplasms, particularly melanomas.1-6</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/138/S-100_4C4-9" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Cytoplasmic labelling by S-100 antibody on melanoma tumor cells.','https://www.cellmarque.com/antibodies/CM/138/S-100_4C4-9','#','https://www.cellmarque.com/cmsial-images/TH_330M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-138-s-100-4c4-9-C4A39C13',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/138/S-100_4C4-9');
Insert into WEB.PRODUCTS_STAGING (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7527','Spectrin',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>RBC2/3D5</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Mouse</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Hematopathology</td></tr>        <tr><th>Visualization:</th><td>membranous</td></tr>        <tr><th>Control:</th><td>bone marrow</td></tr>        <tr><th>Dilution Range:</th><td>1:10-1:100*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Spectrin is a cytoskeletal protein which is found in muscles, red blood cells and red cell precursors. Anti-Spectrin antibody is useful in the identification of blood dyscrasias and muscle disorders.1-3</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/140/Spectrin_RBC2-3D5" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Spectrin antibody labels red blood cell precursors with a membranous pattern.','https://www.cellmarque.com/antibodies/CM/140/Spectrin_RBC2-3D5','#','https://www.cellmarque.com/cmsial-images/TH_333M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-140-spectrin-rbc2-3d5-A92C9C26',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/140/Spectrin_RBC2-3D5');
Insert into WEB.PRODUCTS_STAGING (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7528','Synaptophysin',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>polyclonal</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Rabbit</td></tr>        <tr><th>Antibody Type:</th><td>Polyclonal</td></tr>        <tr><th>Specialties:</th><td>Anatomic Pathology</td></tr>        <tr><th>Visualization:</th><td>cytoplasmic</td></tr>        <tr><th>Control:</th><td>pancreas</td></tr>        <tr><th>Dilution Range:</th><td>1:100-1:500*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Anti-synaptophysin reacts with neuroendocrine cells of human adrenal medulla, carotid body, pituitary, thyroid, pancreas.1-2Positive staining is seen in neurons of the brain. This antibody identifies normal neuroendocrine cells and neuroendocrine neoplasms.1-5Diffuse, finely granular cytoplasmic staining is observed which probably correlates with the distribution of the antigen within neurosecretory vesicles. The expression of synaptophysin is independent of the presence of NSE or other neuroendocrine markers.3Anti-synaptophysin is an independent, broad-range marker of neural and neuroendocrine differentiation. Note:This product has been discontinued.Synaptophysin (EP158)is available as an alternative.</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/141/Synaptophysin_polyclonal" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Pancreatic islet cells are labelled in the cytoplasm by anti-synaptophysin.','https://www.cellmarque.com/antibodies/CM/141/Synaptophysin_polyclonal','#','https://www.cellmarque.com/cmsial-images/TH_336A-7-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-141-synaptophysin-polyclonal-312DD1DD',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/141/Synaptophysin_polyclonal');
Insert into WEB.PRODUCTS_STAGING (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7554','E-cadherin',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>EP700Y</td></tr>        <tr><th>Brand:</th><td>CM + RabMAb</td></tr>        <tr><th>Host:</th><td>Rabbit</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Breast/Gynecological Pathology</td></tr>        <tr><th>Visualization:</th><td></td></tr>        <tr><th>Control:</th><td>Breast (Membranous)</td></tr>        <tr><th>Dilution Range:</th><td>1:50-1:200*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">E-cadherin is a transmembrane protein that is involved in cell adhesion through the formation of adherens junctions between cells. It is expressed in cells of epithelial lineage. Anti-E-cadherin stains positively in glandular epithelium as well as carcinomas of the gastrointestinal tract1and breast. E-cadherin immunohistochemistry may also aid in the differentiation of breast ductal carcinomas (with membranous stain) from lobular carcinomas (with loss of the membranous stain)2,3.</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/1972/E-cadherin_EP700Y" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','E-cadherin (EP700Y) on breast.','https://www.cellmarque.com/antibodies/CM/1972/E-cadherin_EP700Y','#','https://www.cellmarque.com/cmsial-images/TH_246R-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-1972-e-cadherin-ep700y-3638FC68',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/1972/E-cadherin_EP700Y');
Insert into WEB.PRODUCTS_STAGING (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7556','p57Kip2',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>Kp10</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Mouse</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Genitourinary (GU) Pathology</td></tr>        <tr><th>Visualization:</th><td></td></tr>        <tr><th>Control:</th><td>Placenta (Nuclear)</td></tr>        <tr><th>Dilution Range:</th><td>1:100-1:500*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">p57 is a human tumor suppressor gene encoded on the 11p15.5 chromosomal sequence. Anti-p57 has been used as an aid in discriminating complete hydatidiform mole (CHM) (no nuclear labeling of cytotrophoblasts or stromal cells) from partial hydatidiform mole (PHM) (nuclear staining of both cytotrophoblasts and stromal cells) and hydropic abortion. In normal placenta, cytotrophoblast, intermediate trophoblast and decidual cells, and stromal cells are labeled with this antibody. Intervillous trophoblastic islands demonstrate nuclear labeling in all entities and serve as an internal control.1-6</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/1974/p57Kip2_Kp10" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','A nuclear reaction in partial mole labels cytotrophoblastic cells by anti-p57.','https://www.cellmarque.com/antibodies/CM/1974/p57Kip2_Kp10','#','https://www.cellmarque.com/cmsial-images/TH_457M-9-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-1974-p57kip2-kp10-E8BFC852',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/1974/p57Kip2_Kp10');
Insert into WEB.PRODUCTS_STAGING (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7557','Calponin-1',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>EP798Y</td></tr>        <tr><th>Brand:</th><td>CM + RabMAb</td></tr>        <tr><th>Host:</th><td>Rabbit</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Anatomic Pathology</td></tr>        <tr><th>Visualization:</th><td></td></tr>        <tr><th>Control:</th><td>Appendix (Cytoplasmic)</td></tr>        <tr><th>Dilution Range:</th><td>1:50-1:200*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Calponin is a 34-kD polypeptide that interacts with actin, tropomyosin, and calmodulin. It is involved in smooth muscle contraction mechanism and is restricted exclusively to smooth muscle tissue. Anti-calponin has been found to be useful in staining myoepithelium and thus has been used to confirm the presence of myoepithelial cells in benign breast proliferations and their absence in invasive breast carcinomas.1Calponin positivity has also been noted in myoepithelial neoplasms2,4and pleomorphic adenoma3of salivary gland.</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/1975/Calponin-1_EP798Y" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Myoepithelial cells of breast sclerosing adenosis are stained positive in a cytoplasmic pattern.','https://www.cellmarque.com/antibodies/CM/1975/Calponin-1_EP798Y','#','https://www.cellmarque.com/cmsial-images/TH_231R-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-1975-calponin-1-ep798y-3F48F123',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/1975/Calponin-1_EP798Y');
Insert into WEB.PRODUCTS_STAGING (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7558','Ep-CAM/Epithelial Specific Antigen',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>MOC-31</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Mouse</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Anatomic Pathology • Cytopathology</td></tr>        <tr><th>Visualization:</th><td></td></tr>        <tr><th>Control:</th><td>Colon adenocarcinoma (Cytoplasmic, Membranous)</td></tr>        <tr><th>Dilution Range:</th><td>1:50-1:200*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Epithelial cell adhesion molecule (Ep-CAM) is a transmembrane glycoprotein localized on the membrane of cells in most epithelial tissues.1Immunoreactivity with the antibody to Ep-CAM has been seen in the majority of epithelial neoplasms, whereas most non-epithelial neoplasms do not show Ep-CAM expression.2Ep-CAM is not expressed in mesothelial cells, hepatocytes, and lymphocytes.1,2In conjunction with other markers, Ep-CAM can be used as an aid in determining neoplasms of epithelial origin, such as distinguishing between lung adenocarcinoma and mesothelioma.2-4</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/1979/Ep-CAM-Epithelial-Specific-Antigen_MOC-31" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Ep-CAM/Epithelial Specific Antigen (MOC-31) on colon.','https://www.cellmarque.com/antibodies/CM/1979/Ep-CAM-Epithelial-Specific-Antigen_MOC-31','#','https://www.cellmarque.com/cmsial-images/TH_248M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-1979-ep-cam-epithelial-specific-antig-4C2A8F7E',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/1979/Ep-CAM-Epithelial-Specific-Antigen_MOC-31');
