     </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2123/Cytokeratin-14_SP53" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Cytokeratin 14 (SP53) on lung squamous carcinoma.','https://www.cellmarque.com/antibodies/CM/2123/Cytokeratin-14_SP53','#','https://www.cellmarque.com/cmsial-images/TH_314R-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2123-cytokeratin-14-sp53-C1BCBA44',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/2123/Cytokeratin-14_SP53');
Insert into WEB.PRODUCTS_STAGING (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7645','S100P',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>16/f5</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Mouse</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Anatomic Pathology</td></tr>        <tr><th>Visualization:</th><td>cytoplasmic, nuclear</td></tr>        <tr><th>Control:</th><td>pancreatic ductal adenocarcinoma, urothelial carcinoma, placenta</td></tr>        <tr><th>Dilution Range:</th><td>1:100-1:500*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">S100P is a member of the S100 family of proteins. The family is expressed in a wide range of cells and is thought to play a role in cell cycle progression and in differentiation. Anti-S100P with nuclear or nuclear/cytoplasmic immunoreactivity can be seen in pancreatic ductal adenocarcinomas, while it is rarely detectable in benign pancreatic ducts. It may also help to distinguish urothelial carcinomas from other genitourinary neoplasms such as prostate carcinoma.1-6</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2124/S100P_16-f5" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','S100P antibody labels both cytoplasmic and nuclear for tumor cells in pancreatic ductal adenocarcinoma.','https://www.cellmarque.com/antibodies/CM/2124/S100P_16-f5','#','https://www.cellmarque.com/cmsial-images/TH_376M-9-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2124-s100p-16-f5-7D306BE2',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/2124/S100P_16-f5');
