div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/51/CD61_2f2" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Megakaryocytes are strongly highlighted in a cytoplasmic staining reaction.','https://www.cellmarque.com/antibodies/CM/51/CD61_2f2','#','https://www.cellmarque.com/cmsial-images/TH_161M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-51-cd61-2f2-25D8A82D',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/51/CD61_2f2');
