>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/52/CD68_Kp-1" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','CD68 (Kp-1) on tonsil.','https://www.cellmarque.com/antibodies/CM/52/CD68_Kp-1','#','https://www.cellmarque.com/cmsial-images/TH_168M-9-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-52-cd68-kp-1-DFDB34BB',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/52/CD68_Kp-1');
