ge">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Collagen Type IV (CIV22) on lung.','https://www.cellmarque.com/antibodies/CM/61/Collagen-Type-IV_CIV22','#','https://www.cellmarque.com/cmsial-images/TH_239M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-61-collagen-type-iv-civ22-FB4A157E',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/61/Collagen-Type-IV_CIV22');
