e>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/3153/Cytokeratin-17_EP98" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Cytokeratin 17 (EP98) on cervical intraepithelial neoplasia III.','https://www.cellmarque.com/antibodies/CM/3153/Cytokeratin-17_EP98','#','https://www.cellmarque.com/cmsial-images/TH_317R-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-3153-cytokeratin-17-ep98-0618E611',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','CM/3153/Cytokeratin-17_EP98');
